/* Sone Sone Mommy POS — shared receipt template (print + share). Keep this the single source of truth. */
(function () {
  function num(v){ var x = Number(String(v==null?0:v).replace(/[^0-9.\-]/g,"")); return isNaN(x)?0:x; }
  function fmt(n){ return Number(n||0).toLocaleString(); }
  function getNetNumber(s){ return num(s.grandTotal) - num(s.discountAmount) - num(s.deposit) + num(s.delivery); }

  var DEFAULT_LOGO = "";
  var CSS = ".ssm-receipt{width:72mm;max-width:100%;margin:0 auto;background:#fff;padding:4mm;box-sizing:border-box;font-family:'Courier New',monospace;font-size:11px;line-height:1.3;color:#000;}.ssm-receipt .center{text-align:center;}.ssm-receipt hr{border:none;border-top:1px dashed #000;margin:5px 0;}.ssm-receipt .line{display:flex;justify-content:space-between;margin:2px 0;font-family:Arial,sans-serif;font-size:12px;}.ssm-receipt .mm{font-family:Arial,sans-serif;}.ssm-receipt .town-mid{font-family:Arial,sans-serif;font-size:14px;font-weight:bold;}.ssm-receipt .cus-mid{font-family:Arial,sans-serif;font-size:15px;font-weight:bold;}.ssm-receipt .phone-clear{font-family:Arial,sans-serif;font-weight:bold;font-size:14px;}.ssm-receipt .addr-mm{font-family:Arial,sans-serif;font-size:13px;}.ssm-receipt .item-name{font-weight:bold;font-size:12px;margin-top:4px;}.ssm-receipt .item-sub{display:flex;justify-content:space-between;font-size:11px;color:#333;}.ssm-receipt .item-remark{font-size:10px;color:#000;margin-left:4px;}.ssm-receipt .net-box{text-align:center;font-size:13px;font-weight:bold;border:1.5px solid #000;padding:5px;margin:5px 0;}.ssm-receipt .delivery-note{text-align:center;font-family:Arial,sans-serif;font-size:11px;margin:4px 0;}.ssm-receipt .footer-mm{font-family:Arial,sans-serif;text-align:center;font-size:11px;margin-top:6px;line-height:1.4;}";

  function injectCSS(){
    if (document.getElementById("ssm-receipt-css")) return;
    var st = document.createElement("style");
    st.id = "ssm-receipt-css";
    st.textContent = CSS;
    (document.head || document.documentElement).appendChild(st);
  }

  function buildHTML(sale){
    var settings    = JSON.parse(localStorage.getItem("shopSettings")) || {};
    var addrAlign   = settings.addrAlign || "left";
    var footerMsg   = (settings.thankYou || "စုံစုံမာမီရဲ့ လက်ရာလေးကို မြည်းစမ်းကြည့်ပေးလို့ ကျေးဇူးအများကြီး တင်ပါတယ် 🙏<br>စားမြိန်ပါစေနော် 💛").replace(/\n/g, "<br>");
    var shopLogo    = settings.logo    || DEFAULT_LOGO;
    var shopAddress = settings.address || "၀/၁၂၆၊ ဗိုလ်တိုက်ချွန်းလမ်း၊ အောင်ချမ်းသာ (၃) ရပ်ကွက်၊<br>သန်လျင်";
    var shopPhone   = settings.phone   || "09965303525, 09688199078";
    var logoSize    = settings.logoSize  || 115;
    var textSize    = settings.textSize  || 9;

    var now = sale.orderDate ? new Date(sale.orderDate) : new Date();
    var dateTime = now.toLocaleDateString() + "  " +
      now.toLocaleTimeString([], {hour:"2-digit", minute:"2-digit"});

    var itemHtml = "";
    (sale.items || []).forEach(function (item) {
      var giftTag = item.isGift ? " \uD83C\uDF81" : "";
      var subText = "";
      if (item.saleType === "weight") {
        subText = item.weightText ? item.weightText : ((item.size || "") + " | " + item.qty + " x " + item.price);
      } else {
        subText = (item.isGift ? "\u101C\u1000\u103A\u1006\u1031\u102C\u1004\u103A | " : "") + item.qty + " x " + item.price;
      }
      itemHtml += '<div class="item-name mm">' + item.product + giftTag + '</div>';
      itemHtml += '<div class="item-sub mm"><span>' + subText + '</span><span>' + fmt(item.total) + '</span></div>';
      if (item.remark) {
        itemHtml += '<div class="item-remark mm">\u2192 ' + item.remark + '</div>';
      }
    });

    var discountLine = "";
    if (sale.discountAmount && sale.discountAmount > 0) {
      discountLine = '<div class="line"><span>Discount</span><span>-' + fmt(sale.discountAmount) + '</span></div>';
    }

    var payLabel = "\u1021\u102D\u1019\u103A\u101B\u1031\u102C\u1000\u103A\u1004\u103D\u1031\u1001\u103B\u1031";
    if (sale.payStatus === "Prepaid") payLabel = "\u1015\u1005\u1039\u1005\u100A\u103A\u1038\u1016\u102D\u102F\u1038+\u1015\u102D\u102F\u1037\u1001 \u1021\u102C\u1038\u101C\u102F\u1036\u1038\u101B\u103E\u1004\u103A\u1038\u1015\u103C\u102E\u1038";
    else if (sale.payStatus === "Partial") payLabel = "\u1015\u1005\u1039\u1005\u100A\u103A\u1038\u1016\u102D\u102F\u1038\u101B\u103E\u1004\u103A\u1038\u1015\u103C\u102E\u1038 \u1015\u102D\u102F\u1037\u1001 \u101E\u102C\u1000\u1031\u102C\u1000\u103A\u101B\u1014\u103A";

    var netNum = getNetNumber(sale);

    return '' +
      '<div style="display:flex; align-items:center; gap:6px;">' +
        '<img src="' + shopLogo + '" style="width:' + logoSize + 'px; height:auto; flex-shrink:0;">' +
        '<div style="flex:1;">' +
          '<div class="mm" style="font-size:' + textSize + 'px; line-height:1.3; text-align:' + addrAlign + ';">' +
            shopAddress + '<br>\uD83D\uDCDE ' + shopPhone +
          '</div>' +
          '<div class="mm" style="font-size:' + textSize + 'px; line-height:1.5; margin-top:4px; border-top:1px solid #000; padding-top:3px; text-align:right;">' +
            (sale.orderNo || "") + '<br>\u101C\u1000\u103A\u1001\u1036\u101E\u1030-' + (sale.staff || "-") + '<br>' + (sale.orderApp || "-") + '<br>' + (sale.deliveryService || "-") +
          '</div>' +
        '</div>' +
      '</div>' +
      '<hr>' +
      '<div class="line" style="align-items:baseline;">' +
        '<span class="town-mid">' + (sale.township || "-") + '</span>' +
        '<span style="font-size:11px;">' + dateTime + '</span>' +
      '</div>' +
      '<hr>' +
      '<div class="cus-mid">' + (sale.customer || "-") + '</div>' +
      '<div class="phone-clear">' + (sale.phone || "-") + '</div>' +
      '<div class="addr-mm">' + (sale.address || "-") + '</div>' +
      '<hr>' +
      itemHtml +
      '<hr>' +
      '<div class="line"><span>Total</span><span>' + fmt(sale.grandTotal) + '</span></div>' +
      discountLine +
      '<div class="line"><span>Deposit</span><span>' + fmt(sale.deposit) + '</span></div>' +
      '<div class="line"><span>Delivery Fee</span><span>' + fmt(sale.delivery) + '</span></div>' +
      '<div class="net-box mm">' + payLabel + ' : ' + fmt(netNum) + '</div>' +
      (sale.note ? '<div class="delivery-note mm">' + sale.note + '</div>' : "") +
      '<div class="footer-mm">' + footerMsg + '</div>' +
      '<div style="height:22px"></div>';
  }

  window.ssmBuildReceiptHTML = buildHTML;
  window.ssmRenderReceipt = function (el, sale) {
    if (!el || !sale) return;
    injectCSS();
    el.classList.add("ssm-receipt");
    el.innerHTML = buildHTML(sale);
  };
})();
